-- ShippingCow — Migration 005
-- Adds: fedex_zone_chart — USPS domestic zone matrix for 3-warehouse network
-- 2,793 rows covering all US destinations for NJ-089, TX-774, CA-917

CREATE TABLE IF NOT EXISTS fedex_zone_chart (
  id            SERIAL PRIMARY KEY,
  origin_prefix CHAR(3) NOT NULL,
  dest_prefix   CHAR(3) NOT NULL,
  zone          SMALLINT NOT NULL CHECK (zone BETWEEN 1 AND 9),
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(origin_prefix, dest_prefix)
);

-- Index for fast zone lookups: SELECT zone FROM fedex_zone_chart WHERE origin_prefix=$1 AND dest_prefix=$2
CREATE INDEX IF NOT EXISTS idx_zone_lookup ON fedex_zone_chart (origin_prefix, dest_prefix);

